package main

import (
	"database/sql"
	_ "github.com/mattn/go-sqlite3"
	"encoding/json"
	"net/http"
	"strconv"
)

var db *sql.DB

type Todo struct {
	ID    int    `json:"id"`
	Title string `json:"title"`
	Done  bool   `json:"done"`
}

func init() {
	var err error
	db, err = sql.Open("sqlite3", "./todos.db")
	if err != nil {
		panic(err)
	}
	_, err = db.Exec("CREATE TABLE IF NOT EXISTS todos (id INTEGER PRIMARY KEY AUTOINCREMENT, title TEXT, done BOOLEAN)")
	if err != nil {
		panic(err)
	}
}

func todosHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case "GET":
		if r.URL.Query().Get("id") != "" {
			id, _ := strconv.Atoi(r.URL.Query().Get("id"))
			row := db.QueryRow("SELECT id, title, done FROM todos WHERE id = ?", id)
			var t Todo
			err := row.Scan(&t.ID, &t.Title, &t.Done)
			if err != nil {
				http.Error(w, err.Error(), http.StatusInternalServerError)
				return
			}
			json.NewEncoder(w).Encode(t)
		} else {
			rows, err := db.Query("SELECT id, title, done FROM todos")
			if err != nil {
				http.Error(w, err.Error(), http.StatusInternalServerError)
				return
			}
			defer rows.Close()
			var todos []Todo
			for rows.Next() {
				var t Todo
				rows.Scan(&t.ID, &t.Title, &t.Done)
				todos = append(todos, t)
			}
			json.NewEncoder(w).Encode(todos)
		}
	case "POST":
		var t Todo
		json.NewDecoder(r.Body).Decode(&t)
		_, err := db.Exec("INSERT INTO todos (title, done) VALUES (?, ?)", t.Title, t.Done)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		w.Write([]byte("created"))
	case "PUT":
		id, _ := strconv.Atoi(r.URL.Query().Get("id"))
		var t Todo
		json.NewDecoder(r.Body).Decode(&t)
		_, err := db.Exec("UPDATE todos SET title = ?, done = ? WHERE id = ?", t.Title, t.Done, id)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		w.Write([]byte("updated"))
	case "DELETE":
		id, _ := strconv.Atoi(r.URL.Query().Get("id"))
		_, err := db.Exec("DELETE FROM todos WHERE id = ?", id)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		w.Write([]byte("deleted"))
	}
}

func main() {
	fs := http.FileServer(http.Dir("./static"))
	http.Handle("/", fs)
	http.HandleFunc("/todos", todosHandler)
	http.ListenAndServe(":8080", nil)
}

package main

import (
	"database/sql"
	_ "github.com/go-sql-driver/mysql"
	"encoding/json"
	"net/http"
	"strconv"
)

var db *sql.DB

type Todo struct {
	ID    int    `json:"id"`
	Title string `json:"title"`
	Done  bool   `json:"done"`
}

func init() {
	var err error
	db, err = sql.Open("mysql", "user:password@tcp(127.0.0.1:3306)/todos_db")
	if err != nil {
		panic(err)
	}
	_, err = db.Exec("CREATE TABLE IF NOT EXISTS todos (id INT AUTO_INCREMENT PRIMARY KEY, title VARCHAR(255), done BOOLEAN)")
	if err != nil {
		panic(err)
	}
}

func todosHandler(w http.ResponseWriter, r *http.Request) {
	switch r.Method {
	case "GET":
		rows, err := db.Query("SELECT id, title, done FROM todos")
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		defer rows.Close()
		var todos []Todo
		for rows.Next() {
			var t Todo
			rows.Scan(&t.ID, &t.Title, &t.Done)
			todos = append(todos, t)
		}
		json.NewEncoder(w).Encode(todos)
	case "POST":
		var t Todo
		json.NewDecoder(r.Body).Decode(&t)
		_, err := db.Exec("INSERT INTO todos (title, done) VALUES (?, ?)", t.Title, t.Done)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		w.Write([]byte("created"))
	case "PUT":
		id := r.URL.Query().Get("id")
		var t Todo
		json.NewDecoder(r.Body).Decode(&t)
		_, err := db.Exec("UPDATE todos SET title=?, done=? WHERE id=?", t.Title, t.Done, id)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		w.Write([]byte("updated"))
	case "DELETE":
		id := r.URL.Query().Get("id")
		_, err := db.Exec("DELETE FROM todos WHERE id=?", id)
		if err != nil {
			http.Error(w, err.Error(), http.StatusInternalServerError)
			return
		}
		w.Write([]byte("deleted"))
	}
}

func main() {
	http.HandleFunc("/todos", todosHandler)
	http.ListenAndServe(":8080", nil)
}
